<?php
namespace App\Http\Controllers\Api; use App\Http\Controllers\Controller; use App\Http\Resources\MoveResource; use App\Models\Move; use Illuminate\Http\Request;
class MoveController extends Controller { public function index(){return MoveResource::collection(Move::with(['player','card'])->latest()->get());} public function store(Request $r){return new MoveResource(Move::create($r->validate(['game_id'=>'required|exists:games,id','player_id'=>'required|exists:users,id','card_id'=>'nullable|exists:cards,id','correct'=>'required|boolean'])));} public function show(Move $move){return new MoveResource($move->load(['player','card']));} public function update(Request $r,Move $move){$move->update($r->validate(['correct'=>'sometimes|boolean']));return new MoveResource($move);} public function destroy(Move $move){$move->delete();return response()->noContent();} }
